  json: {
    event: {
      event_type: eventType,
      text,
      chatId: String(chatIdRaw || ''),
      chat_id: String(chatIdRaw || ''),
      userId: String(userIdRaw || ''),
      messageId: String(messageIdRaw || ''),
      timestamp: Date.now(),
      callback_query: callbackData ? { data: callbackData } : null,
      deep_link: deepLink,
    },
  },
}];

const payload = $json ?? {};
let event = payload.event ?? null;

const readEventFromNode = (nodeName) => {
  try {
    const nodeRef = $(nodeName);
    if (!nodeRef || !nodeRef.isExecuted) return null;
    const candidate = nodeRef.first()?.json?.event;
    return candidate && typeof candidate === 'object' ? candidate : null;
  } catch {
    return null;
  }
