  const needFreshProductAnchor = !hasProductContext && !shouldContinueContext;
  if (needFreshProductAnchor) {
    if (hasKnownBrand && !hasKnownModel) computedMissingFields.push('model');
    else if (!hasKnownBrand && !hasKnownModel) computedMissingFields.push('brand_or_model');
  }
}
if (effectiveFlow === 'exchange' && missingInformation.length === 0) {
  const needProductAnchor = !currentInterest && shownProducts.length === 0;
  if (needProductAnchor) {
    if (hasKnownBrand && !hasKnownModel) computedMissingFields.push('model');
    else if (!hasKnownBrand && !hasKnownModel) computedMissingFields.push('brand_or_model');
  }
  if (!mergedConstraints.condition) computedMissingFields.push('condition');
}
const missing_fields = missingInformation.length > 0 ? missingInformation.slice() : computedMissingFields;
if (effectiveFlow === 'exchange' && !mergedConstraints.condition && !missing_fields.includes('condition')) {
  missing_fields.push('condition');
}
if (effectiveFlow === 'exchange' && missing_fields.length > 2) {
  missing_fields.length = 2;
}
const last_asked_key = requestedLastAskedKey ?? missing_fields[0] ?? null;

const productContext = {
  brand: mergedConstraints.brand,
  model: mergedConstraints.model,
  storage: mergedConstraints.storage,
  condition: mergedConstraints.condition,
  budget_etb: mergedConstraints.budget_etb,
  current_interest: currentInterest ? currentInterest.raw : null,
  current_topic: currentTopic,
  current_flow: currentFlow,
};

let rules_output = {
  reply_mode: shouldContinueContext ? 'resume_previous_flow' : 'off_topic_redirect',
  should_call_resolver: false,
  resolver_input: {
    flow: effectiveFlow,
    product_context: productContext,
    missing_fields,
    resolved_reference: resolvedProduct ? { id: resolvedProduct.id, raw: resolvedProduct.raw } : null,
    resolved_product_name: resolvedProduct?.name ?? null,
  },
  session_update: {
    last_topic: effectiveTopic,
    flow_stage: shouldContinueContext ? (currentFlow ?? effectiveFlow) : effectiveFlow,
    ambiguous_reference: reference_resolution.reference_type !== 'none' ? reference_resolution.reference_type : null,
    resolved_ambiguity: reference_resolution.resolved,
    collected_constraints: mergedConstraints,
    last_asked_key,
  },
  confidence,
  reasoning: shouldContinueContext ? 'default_resume_previous_flow' : 'default_off_topic_redirect',
};

if (event.event_type === 'start_reset') {
  rules_output = {
    ...rules_output,
    reply_mode: 'small_talk_redirect',
    should_call_resolver: false,
    session_update: {
      ...rules_output.session_update,
      last_topic: null,
      flow_stage: null,
      ambiguous_reference: null,
      resolved_ambiguity: false,
      last_asked_key: null,
    },
    reasoning: 'start_reset_welcome',
  };
} else if (event.event_type === 'deep_link_start') {
  rules_output = {
    ...rules_output,
    reply_mode: 'business_resolve',
    should_call_resolver: true,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: 'buy',
      missing_fields: [],
    },
    session_update: {
      ...rules_output.session_update,
      last_topic: 'product',
      flow_stage: 'buy',
      last_asked_key: null,
    },
    reasoning: 'deep_link_start_business_entry',
  };
} else if (!Number.isFinite(confidence) || confidence < 0.6) {
  rules_output = {
    ...rules_output,
    reply_mode: shouldContinueContext && currentFlow ? 'resume_previous_flow' : 'handoff_admin',
    should_call_resolver: Boolean(shouldContinueContext && currentFlow),
    reasoning: shouldContinueContext && currentFlow ? 'low_confidence_but_context_preserved' : 'low_understanding_confidence',
  };
} else if (messageFunction === 'acknowledgment') {
  const shouldOpenLightConversation = Boolean(
    Number(session.message_count ?? 0) === 0
    && !currentFlow
    && !currentTopic
    && shownProducts.length === 0
    && !currentInterest
    && !Object.values(mergedConstraints).some((value) => value !== null)
  );
  rules_output = {
    ...rules_output,
    reply_mode: shouldOpenLightConversation ? 'small_talk_redirect' : 'acknowledge_and_close',
    should_call_resolver: false,
    reasoning: shouldOpenLightConversation ? 'acknowledgment_first_turn_redirect' : 'acknowledgment_detected',
  };
} else if (messageFunction === 'clarification') {
  rules_output = {
    ...rules_output,
    reply_mode: hasActiveContext ? 'clarify_reference' : 'handoff_admin',
    should_call_resolver: false,
    reasoning: hasActiveContext ? 'clarification_with_existing_context' : 'clarification_without_context',
  };
} else if (businessIntent === 'store_info' || understandingTopic === 'store_info' || understandingTopic === 'location' || (messageFunction === 'info_request' && (businessIntent === null || businessIntent === 'store_info'))) {
  rules_output = {
    ...rules_output,
    reply_mode: 'business_resolve',
    should_call_resolver: true,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: 'info',
      missing_fields: [],
    },
    session_update: {
      ...rules_output.session_update,
      last_topic: understandingTopic ?? 'store_info',
      flow_stage: shouldContinueContext ? (currentFlow ?? null) : 'info',
      last_asked_key: null,
    },
    reasoning: 'store_info_bypasses_product_flow',
  };
} else if (businessIntent === 'support') {
  rules_output = {
    ...rules_output,
    reply_mode: shouldContinueContext && currentFlow ? 'resume_previous_flow' : 'business_resolve',
    should_call_resolver: true,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: 'support',
      missing_fields: [],
    },
    session_update: {
      ...rules_output.session_update,
      last_topic: understandingTopic ?? 'support',
      flow_stage: shouldContinueContext ? (currentFlow ?? 'support') : 'support',
      last_asked_key: null,
    },
    reasoning: 'support_request_routed',
  };
} else if (messageFunction === 'negotiation') {
  const negotiationFlow = currentFlow === 'exchange' ? 'exchange' : (intentFlow ?? currentFlow ?? 'buy');
  const hasAnchoredContext = Boolean(
    session.flow_context?.buy_flow?.current_interest
  );
  rules_output = {
    ...rules_output,
    reply_mode: hasAnchoredContext ? 'resume_previous_flow' : 'business_resolve',
    should_call_resolver: hasAnchoredContext ? false : true,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: negotiationFlow,
      missing_fields: [],
    },
    session_update: {
      ...rules_output.session_update,
      flow_stage: negotiationFlow,
      last_asked_key: null,
    },
    reasoning: hasAnchoredContext
      ? 'negotiation_anchored_to_existing_interest'
      : (hasProductContext || hasActiveContext ? 'negotiation_business_resolve_with_context' : 'negotiation_business_resolve_without_context'),
  };
} else if (messageFunction === 'refinement') {
  if (!shouldContinueContext) {
    rules_output.resolver_input.product_context = { budget_etb: mergedConstraints.budget_etb, brand: null, model: null, storage: null, condition: null, current_interest: null, current_topic: null, current_flow: null };
    rules_output.session_update.collected_constraints = { budget_etb: mergedConstraints.budget_etb, brand: null, model: null, storage: null, condition: null };
    rules_output.resolver_input.resolved_reference = null;
  }
  rules_output = {
    ...rules_output,
    reply_mode: shouldContinueContext ? 'resume_previous_flow' : 'business_resolve',
    should_call_resolver: true,
    session_update: {
      ...rules_output.session_update,
      flow_stage: shouldContinueContext ? (currentFlow ?? effectiveFlow) : effectiveFlow,
      last_asked_key,
    },
    reasoning: shouldContinueContext ? 'refinement_reuses_session_context' : 'refinement_with_model_switch',
  };
} else if (messageFunction === 'fresh_request') {
  const isBusiness = businessIntent !== null;
  if (isBusiness) {
    rules_output.resolver_input.product_context = { budget_etb: null, brand: null, model: null, storage: null, condition: null, current_interest: null, current_topic: null, current_flow: null };
    rules_output.session_update.collected_constraints = { budget_etb: null, brand: null, model: null, storage: null, condition: null };
    rules_output.resolver_input.resolved_reference = null;
  }
  rules_output = {
    ...rules_output,
    reply_mode: isBusiness ? 'business_resolve' : 'off_topic_redirect',
    should_call_resolver: isBusiness,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: intentFlow ?? effectiveFlow,
    },
    session_update: {
      ...rules_output.session_update,
      flow_stage: intentFlow ?? effectiveFlow,
      last_asked_key,
    },
    reasoning: isBusiness ? 'fresh_business_request' : 'fresh_non_business_message',
  };
}

return [{ json: { event, session, client_config, understanding_output, understanding_meta, rules_output } }];

parameters.jsonBody:
={{ JSON.stringify({
  sellerId: (() => {
    const cfg = $json.client_config;
    if (cfg && typeof cfg.store_name === 'string' && cfg.store_name.trim()) {
      return cfg.store_name.trim().toLowerCase();
    }
    return 'tedytech';
  })(),
  phoneType: (() => {
    const cleanPhoneType = (value) => {
      if (typeof value !== 'string') return null;
      const normalized = value
        .replace(/\b(32|64|128|256|512|1024)\s*gb\b/ig, ' ')
        .replace(/\b(iphone|samsung|pixel|redmi|xiaomi|tecno|infinix|oppo|vivo|realme|itel|nokia)(\d)/ig, '$1 $2')
        .replace(/\b(pro)(max)\b/ig, '$1 $2')
        .replace(/\s+/g, ' ')
        .trim();
      return normalized || null;
    };
    const text = String($json.event?.text || '').trim();
    const extractFromText = (value) => {
      const source = String(value || '').trim();
      if (!source) return null;
      const match = source.match(/\b(?:iphone\s*\d+(?:\s*(?:pro\s*max|pro|max|plus|mini))?|samsung\s*[a-z0-9+ ]+|pixel\s*[a-z0-9+ ]+|redmi\s*[a-z0-9+ ]+|xiaomi\s*[a-z0-9+ ]+|tecno\s*[a-z0-9+ ]+|infinix\s*[a-z0-9+ ]+|oppo\s*[a-z0-9+ ]+|vivo\s*[a-z0-9+ ]+|realme\s*[a-z0-9+ ]+|itel\s*[a-z0-9+ ]+|nokia\s*[a-z0-9+ ]+)\b/i);
      return cleanPhoneType(match ? match[0] : null);
    };
    const explicit = cleanPhoneType($json.rules_output?.resolver_input?.resolved_product_name || null);
    if (explicit) return explicit;
    const fromText = extractFromText(text);
    if (fromText) return fromText;
    const ref = $json.understanding_output?.reference_resolution?.refers_to;
    if (typeof ref === 'string') {
      const normalized = cleanPhoneType(ref);
      const blocked = ['desired_phone', 'current_phone', 'last_shown_option', 'cheaper_option', 'previous_selection', 'none'];
      if (normalized && !blocked.includes(normalized.toLowerCase())) return normalized;
    }
    const fromContext = cleanPhoneType(([
      $json.rules_output?.resolver_input?.product_context?.brand,
      $json.rules_output?.resolver_input?.product_context?.model,
    ].filter(Boolean).join(' ').trim() || [
      $json.session?.collected_constraints?.brand,
      $json.session?.collected_constraints?.model,
    ].filter(Boolean).join(' ').trim()));
    if (fromContext) return fromContext;
    return null;
  })(),
  storage: (() => {
    const s = $json.rules_output?.resolver_input?.product_context?.storage
      ?? $json.session?.collected_constraints?.storage
      ?? null;
    if (typeof s !== 'string' || !s.trim()) return null;
    const m = s.match(/\b(32|64|128|256|512|1024)\s*gb\b/i);
    return m ? (m[1] + 'GB') : null;
  })(),
}) }}

parameters.jsCode:
const RULES_NODE = 'Rules Layer';
let base = {};
try {
  const ref = $item(0).$node[RULES_NODE].json;
  if (!ref || !ref.rules_output) {
    console.error(JSON.stringify({ node: 'Business Data Resolver', error: 'cross_node_ref_empty_or_no_rules', ref_node: RULES_NODE }));
  }
  base = ref ?? {};
} catch (e) {
  console.error(JSON.stringify({ node: 'Business Data Resolver', error: 'cross_node_ref_failed', ref_node: RULES_NODE, message: e.message }));
}
const event = base.event && typeof base.event === 'object' ? base.event : {};
const session = base.session && typeof base.session === 'object' ? base.session : {};
const client_config = base.client_config && typeof base.client_config === 'object' ? base.client_config : {};
const understanding_output = base.understanding_output && typeof base.understanding_output === 'object' ? base.understanding_output : {};
const rules_output = base.rules_output && typeof base.rules_output === 'object' ? base.rules_output : {};
const resolverInput = rules_output.resolver_input && typeof rules_output.resolver_input === 'object' ? rules_output.resolver_input : {};
const inputItems = $input.all().map((item) => item.json ?? {});

const isRecord = (value) => !!value && typeof value === 'object' && !Array.isArray(value);
const normalizeText = (value) => typeof value === 'string' && value.trim() ? value.trim() : null;
const normalizeNullableNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : null;
};
const normalizeStorageValue = (value) => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (!trimmed) return null;
  const gbMatch = trimmed.match(/\b(32|64|128|256|512|1024)\b/i);
  return gbMatch ? (gbMatch[1] + 'GB') : trimmed;
};
const extractStorage = (value) => {
  if (typeof value !== 'string') return null;
  const match = value.match(/\b(32|64|128|256|512|1024)\s*gb\b/i);
  return match ? (match[1] + 'GB') : null;
};
const normalizeProduct = (value, index) => {
  if (value === null || value === undefined || !isRecord(value)) return null;
  const priceValue = value.price_etb ?? value.price ?? value.amount ?? null;
  const stockQty = normalizeNullableNumber(value.stockQuantity ?? value.stock_quantity ?? value.stock ?? null);
  return {
    id: String(value.id ?? value._id ?? value.product_id ?? value.sku ?? ('product_' + index)),
    brand: normalizeText(value.brand),
    model: normalizeText(value.model ?? value.phoneType ?? value.name ?? value.title),
    price_etb: normalizeNullableNumber(priceValue),
    storage: normalizeStorageValue(String(value.storage ?? '')),
    ram: value.ram === null || value.ram === undefined ? null : String(value.ram),
    condition: normalizeText(value.condition),
    stock_status: stockQty === null ? null : (stockQty > 0 ? 'in_stock' : 'out_of_stock'),
    stock_quantity: stockQty,
    raw: value,
  };
};
const looksLikeProductRecord = (value) => isRecord(value) && ['id', '_id', 'product_id', 'sku', 'brand', 'model', 'phoneType', 'name', 'title', 'price', 'price_etb', 'amount'].some((key) => Object.prototype.hasOwnProperty.call(value, key));
const collectRemoteProducts = (items) => {
  const flattened = [];
  for (const item of items) {
    if (Array.isArray(item)) {
      flattened.push(...item.filter(looksLikeProductRecord));
      continue;
    }
    if (isRecord(item) && Array.isArray(item.products)) {
      flattened.push(...item.products.filter(looksLikeProductRecord));
      continue;
    }
    if (looksLikeProductRecord(item)) {
      flattened.push(item);
    }
  }
  const deduped = [];
  const seen = new Set();
  for (const value of flattened) {
    const normalized = normalizeProduct(value, deduped.length + 1);
    if (!normalized) continue;
    if (seen.has(normalized.id)) continue;
    seen.add(normalized.id);
    deduped.push(normalized);
  }
  return deduped;
};

const remoteProducts = collectRemoteProducts(inputItems);
let result_mode = remoteProducts.length > 0 ? 'products_found' : 'no_products';
const products = remoteProducts;

const shownProducts = Array.isArray(session.flow_context?.buy_flow?.shown_products)
  ? session.flow_context.buy_flow.shown_products.map(normalizeProduct).filter(Boolean)
  : [];
const currentInterest = normalizeProduct(session.flow_context?.buy_flow?.current_interest, shownProducts.length + 10);
const sessionConstraintsSource = isRecord(session.collected_constraints) ? session.collected_constraints : {};
const sessionConstraints = {
  budget_etb: normalizeNullableNumber(sessionConstraintsSource.budget_etb),
  brand: normalizeText(sessionConstraintsSource.brand ?? currentInterest?.brand ?? null),
  model: normalizeText(sessionConstraintsSource.model ?? currentInterest?.model ?? null),
  storage: normalizeStorageValue(sessionConstraintsSource.storage ?? currentInterest?.storage ?? null),
  condition: normalizeText(sessionConstraintsSource.condition ?? currentInterest?.condition ?? null),
};
const productContextSource = isRecord(resolverInput.product_context) ? resolverInput.product_context : {};
let effectiveConstraints = {
  budget_etb: Object.prototype.hasOwnProperty.call(productContextSource, 'budget_etb') ? normalizeNullableNumber(productContextSource.budget_etb) : sessionConstraints.budget_etb,
  brand: Object.prototype.hasOwnProperty.call(productContextSource, 'brand') ? normalizeText(productContextSource.brand) : sessionConstraints.brand,
  model: Object.prototype.hasOwnProperty.call(productContextSource, 'model') ? normalizeText(productContextSource.model) : sessionConstraints.model,
  storage: Object.prototype.hasOwnProperty.call(productContextSource, 'storage') ? normalizeStorageValue(productContextSource.storage) : (sessionConstraints.storage ?? extractStorage(String(event.text ?? ''))),
  condition: Object.prototype.hasOwnProperty.call(productContextSource, 'condition') ? normalizeText(productContextSource.condition) : sessionConstraints.condition,
};

const candidateProducts = products.length > 0 ? products : shownProducts;
const productNameForMatch = (product) => [product.brand, product.model].filter(Boolean).join(' ').trim().toLowerCase();
let constraintMatchFailed = false;
const isNonProductFlow = resolverInput.flow === 'info' || resolverInput.flow === 'support';
if (products.length > 0) {
  if (effectiveConstraints.model) {
    const hasModelMatch = candidateProducts.some((product) => productNameForMatch(product).includes(effectiveConstraints.model.toLowerCase()));
    if (!hasModelMatch) constraintMatchFailed = true;
  }
  if (effectiveConstraints.brand && !constraintMatchFailed) {
    const hasBrandMatch = candidateProducts.some((product) => product.brand && product.brand.toLowerCase().includes(effectiveConstraints.brand.toLowerCase()));
    if (!hasBrandMatch) constraintMatchFailed = true;
  }
  if (effectiveConstraints.storage) {
    const hasStorageMatch = candidateProducts.some((product) => product.storage && normalizeStorageValue(product.storage) === normalizeStorageValue(effectiveConstraints.storage));
    if (!hasStorageMatch) effectiveConstraints = { ...effectiveConstraints, storage: null };
  }
  if (effectiveConstraints.condition) {
    const hasConditionMatch = candidateProducts.some((product) => product.condition && product.condition.toLowerCase() === effectiveConstraints.condition.toLowerCase());
    if (!hasConditionMatch) effectiveConstraints = { ...effectiveConstraints, condition: null };
  }
}
const requestedName = normalizeText(resolverInput.resolved_product_name)
  ?? ([effectiveConstraints.brand, effectiveConstraints.model].filter(Boolean).join(' ').trim() || null);
let selectedProduct = null;
if (resolverInput.resolved_reference?.id) {
  selectedProduct = candidateProducts.find((product) => product.id === resolverInput.resolved_reference.id) ?? null;
}
if (!selectedProduct && requestedName) {
  const lowered = requestedName.toLowerCase();
  selectedProduct = candidateProducts.find((product) => {
    const name = productNameForMatch(product);
    return Boolean(name) && name === lowered;
  }) ?? null;
}
const isContinuationFlow = ['refinement', 'negotiation'].includes(understanding_output?.message_function ?? '');
if (!selectedProduct && currentInterest && products.length === 0 && isContinuationFlow) {
  const sameModel = effectiveConstraints.model && currentInterest.model && currentInterest.model.toLowerCase() === effectiveConstraints.model.toLowerCase();
  const sameBrand = effectiveConstraints.brand && currentInterest.brand && currentInterest.brand.toLowerCase() === effectiveConstraints.brand.toLowerCase();
  if (!effectiveConstraints.model || sameModel || sameBrand) {
    selectedProduct = currentInterest;
  }
}

const matchesConstraints = (product) => {
  if (!product) return false;
  if (effectiveConstraints.brand && (!product.brand || !product.brand.toLowerCase().includes(effectiveConstraints.brand.toLowerCase()))) return false;
  if (effectiveConstraints.model) {
    const name = productNameForMatch(product);
    if (!name.includes(effectiveConstraints.model.toLowerCase())) return false;
  }
  if (effectiveConstraints.storage && (!product.storage || normalizeStorageValue(product.storage) !== normalizeStorageValue(effectiveConstraints.storage))) return false;
  if (effectiveConstraints.condition && (!product.condition || product.condition.toLowerCase() !== effectiveConstraints.condition.toLowerCase())) return false;
  return true;
};

const filteredProducts = candidateProducts.filter(matchesConstraints);
const effectiveProducts = filteredProducts.length > 0 ? filteredProducts : (products.length > 0 ? candidateProducts : []);
const replyProducts = selectedProduct
  ? [selectedProduct]
  : effectiveProducts.slice(0, 5);
const numericPrices = replyProducts.map((product) => product.price_etb).filter((value) => Number.isFinite(value));
const priceRange = numericPrices.length > 0 ? { min: Math.min(...numericPrices), max: Math.max(...numericPrices) } : null;
let result_type = 'no_match';
let next_step = 'ask_clarification';
let exchange_context = null;
const isExchangeClarification = resolverInput.flow === 'exchange'
  && Array.isArray(resolverInput.missing_fields)
  && resolverInput.missing_fields.length > 0;
const exchangeContext = resolverInput.flow === 'exchange'
  ? {
      current_interest: session.flow_context?.buy_flow?.current_interest ?? null,
      collected_constraints: effectiveConstraints,
    }
  : null;

if (rules_output.reply_mode === 'clarify_reference') {
  result_type = 'clarification_needed';
  next_step = 'ask_clarification';
} else if (isExchangeClarification) {
  result_type = 'clarification_needed';
  next_step = 'ask_clarification';
  exchange_context = exchangeContext;
} else if (resolverInput.flow === 'exchange') {
  result_type = 'exchange_offer';
  next_step = 'ask_clarification';
  exchange_context = exchangeContext;
} else if (resolverInput.flow === 'info' || resolverInput.flow === 'support') {
  result_type = 'store_info';
  result_mode = 'info';
  next_step = 'direct_answer';
} else if (selectedProduct) {
  result_type = 'single_product';
  next_step = 'show_single';
} else if (effectiveProducts.length > 1) {
  result_type = 'multiple_options';
  next_step = 'show_options';
} else if (effectiveProducts.length === 1) {
  result_type = 'single_product';
  next_step = 'show_single';
} else if ((resolverInput.missing_fields ?? []).length > 0) {
  result_type = 'clarification_needed';
  next_step = 'ask_clarification';
}
if (!isNonProductFlow && constraintMatchFailed && result_type !== 'clarification_needed' && result_type !== 'exchange_offer') {
  result_type = 'no_match';
  next_step = 'ask_clarification';
}

const isNewProductFocus = !currentInterest || (replyProducts[0] && replyProducts[0].id !== currentInterest.id);
const post_price_mode =
  result_type === 'single_product'
  && replyProducts.length === 1
  && resolverInput.flow === 'buy'
  && isNewProductFocus
    ? 'price_shown'
    : null;
const exchange_invitation_variant =
  post_price_mode === 'price_shown'
    ? ((Number.isFinite(Number(session.message_count ?? null)) ? Number(session.message_count) : 0) % 4) + 1
    : null;
const product_detail_fields = (() => {
  if (post_price_mode !== 'price_shown' || !replyProducts[0]) return [];
  const product = replyProducts[0];
  const isApple = (product.brand ?? '').toLowerCase() === 'apple' || (product.model ?? '').toLowerCase().includes('iphone');
  return ['storage', 'ram', 'condition']
    .filter((key) => {
      if (key === 'ram' && isApple) return false;
      return product[key] != null;
    })
    .map((key) => ({ key, value: String(product[key]) }));
})();
const exchange_collection = resolverInput.flow === 'exchange'
  ? (() => {
      const target_phone_raw = session.flow_context?.buy_flow?.current_interest;
      const target_phone = isRecord(target_phone_raw)
        ? {
            brand: normalizeText(target_phone_raw.brand ?? null),
            model: normalizeText(target_phone_raw.model ?? target_phone_raw.phoneType ?? null),
            storage: normalizeStorageValue(target_phone_raw.storage ?? null),
          }
        : null;
      const exchangeDetails = isRecord(session.exchange_details) ? session.exchange_details : {};
      const collectedConstraints = isRecord(session.collected_constraints) ? session.collected_constraints : {};
      return {
        target_phone,
        collected: {
          model: normalizeText(exchangeDetails.model ?? collectedConstraints.model ?? null),
          storage: normalizeStorageValue(exchangeDetails.storage ?? collectedConstraints.storage ?? null),
          ram: exchangeDetails.ram === null || exchangeDetails.ram === undefined ? null : String(exchangeDetails.ram),
          condition: normalizeText(exchangeDetails.condition ?? collectedConstraints.condition ?? null),
          battery_health: exchangeDetails.battery_health === null || exchangeDetails.battery_health === undefined ? null : String(exchangeDetails.battery_health),
        },
      };
    })()
  : null;

const resolver_output = {
  result_mode,
  result_type,
  products: replyProducts,
  exchange_context,
  next_step,
  post_price_mode,
  exchange_invitation_variant,
  product_detail_fields,
  exchange_collection,
  facts_for_reply: {
    product_found: Boolean(selectedProduct || replyProducts.length > 0),
    how_many_options: replyProducts.length,
    stock_status: selectedProduct?.stock_status ?? (replyProducts[0]?.stock_status ?? null),
    price_range: priceRange,
  },
};

return [{
  json: {
    event,
    session,
    client_config,
    understanding_output,
    rules_output,
    result_mode,
    products,
    resolver_output,
  },
}];

parameters.jsonBody:
={{ JSON.stringify({
  model: 'google/gemini-3.1-flash-lite-preview',
  temperature: 0.05,
  response_format: { type: 'json_object' },
